9	
10	  async function handleSubmit(e: React.FormEvent<HTMLFormElement>) {
11	    e.preventDefault();
12	    setSaving(true);
13	    setError("");
14	    setSuccess("");
15	
16	    const form = new FormData(e.currentTarget);
17	    const body = {
18	      name: form.get("name"),
19	      email: form.get("email"),
20	      message: form.get("message") || null,
21	    };
22	
23	    try {
24	      const res = await fetch("/api/clients/invitations", {
25	        method: "POST",
26	        headers: { "Content-Type": "application/json" },
27	        credentials: "include",
28	        body: JSON.stringify(body),
29	      });
30	      const data = await res.json();
31	      if (!res.ok) {
32	        setError(data.error || "Failed to send invitation");
33	        return;
34	      }
35	      if (data.invitation.status === "accepted") {
36	        setSuccess(`${body.name} is already on PropStealth — they've been added as your client!`);
37	      } else {
38	        setSuccess(`Invitation sent to ${body.email}`);
39	      }
40	      e.currentTarget.reset();
41	    } catch {
42	      setError("Network error");
43	    } finally {
44	      setSaving(false);
45	    }
46	  }
47	
48	  return (
49	    <div>
50	      {/* Header */}
51	      <div className="mb-5">
52	        <h1 className="text-lg font-semibold text-gray-900">Invite Client</h1>
53	        <p className="text-xs text-gray-500">
54	          Send an invitation to a property owner to join PropStealth as your
55	          client.
56	        </p>
57	      </div>
58	
59	      {/* Form */}
60	      <div className="border border-gray-200 rounded-lg p-5 max-w-[480px]">
61	        <form onSubmit={handleSubmit} className="space-y-4">
62	          {/* Client Name */}
63	          <div>
64	            <label className="block text-xs font-medium text-gray-700 mb-1.5">
65	              Client Name
66	            </label>
67	            <input
68	              name="name"
69	              type="text"
70	              required
71	              placeholder="Full name"
72	              className="w-full border border-gray-300 rounded-md px-3 py-2 text-xs text-gray-900 placeholder-gray-400 focus:outline-none focus:ring-1 focus:ring-brand focus:border-brand"
73	            />
74	          </div>
75	
76	          {/* Email Address */}
77	          <div>
78	            <label className="block text-xs font-medium text-gray-700 mb-1.5">
79	              Email Address
80	            </label>
81	            <input
82	              name="email"
83	              type="email"
