    if (result.rows.length === 0) {
      res.json({ evaluation: null });
      return;
    }
    res.json({ evaluation: result.rows[0] });
  } catch (err) {
    console.error("Get evaluation error:", err);
    res.status(500).json({ error: "Failed to get evaluation" });
