      });
      if (!r.ok) throw new Error((await r.json()).error || "Failed");
      await loadAll();
    } catch (e) {
      setMsg((e as Error).message);
    } finally {
      setBusy(false);
    }
  }

  async function reopen() {
    setBusy(true);
    try {
      const r = await fetch(`/api/tenants/${params.id}/reopen`, {
        method: "POST",
